import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface FileTypeBreakdown {
  type: string;
  spaceUsed: number;
}

interface StorageData {
  storage: {
    totalSpace: string;
    usedSpace: string;
    freeSpace: string;
  };
  fileTypeBreakdown: FileTypeBreakdown[];
}

export default function Widget() {
  const storageData = response.data as StorageData;
  const { storage, fileTypeBreakdown } = storageData;

  const pieData = fileTypeBreakdown.map((fileType) => ({
    id: fileType.type,
    value: fileType.spaceUsed,
    label: fileType.type,
  }));

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#1A202C', color: '#E2E8F0' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#F56565' }}>
              Storage Usage
            </Typography>
            <Typography variant="body2">
              Total Space: {storage.totalSpace}
            </Typography>
            <Typography variant="body2">
              Used Space: {storage.usedSpace}
            </Typography>
            <Typography variant="body2">
              Free Space: {storage.freeSpace}
            </Typography>
          </Box>

          <PieChart
            height={200}
            series={[
              {
                data: pieData,
                innerRadius: 0.6,
                outerRadius: 1,
                label: { show: false },
                colors: ['#F56565', '#ED8936', '#ECC94B', '#48BB78', '#4299E1'],
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
